// ─── Fusion par_canton → sheets au chargement ────────────────────────────
// Pour les élections cantonales (Départementales / Cantonales), les données sont
// stockées dans `el.par_canton[cid].sheets[tour][bureauId]` (une sub-sheet par canton,
// car chaque canton a ses propres candidats/binômes). On les "applatit" dans
// `el.sheets` pour que tout le code consommateur (LRVcarte, LRVanalyse, daily-capture)
// fonctionne sans modification : chaque bureau a UN seul jeu de données (celui de
// son canton d'appartenance). par_canton reste accessible pour ceux qui veulent
// lire séparément par canton (ex. UI dédiée).
(function(){
  if (typeof ELECTIONS === 'undefined') return;
  Object.values(ELECTIONS).forEach(el => {
    if (!el.par_canton) return;
    el.sheets = el.sheets || {};
    Object.entries(el.par_canton).forEach(([cid, cd]) => {
      Object.entries(cd.sheets || {}).forEach(([tour, sh]) => {
        el.sheets[tour] = el.sheets[tour] || {};
        Object.entries(sh).forEach(([bid, data]) => {
          el.sheets[tour][bid] = data;
        });
      });
    });
  });
})();

// ─── Conversion voix → pourcentages au chargement ────────────────────────
// `bd.c` est stocké en VOIX entières (issu des xlsx). On convertit en pct
// de haute précision pour que tout le code consommateur ait des valeurs qui
// somment exactement à 100 % par bureau (élimine les arrondis cumulés).
(function(){
  if (typeof ELECTIONS === 'undefined') return;
  Object.values(ELECTIONS).forEach(el => {
    Object.values(el.sheets || {}).forEach(sheet => {
      Object.values(sheet).forEach(bd => {
        // Guard idempotence : si bd._voix est déjà posé, la conversion a déjà eu
        // lieu (bd.c contient les pct). Skip pour ne pas re-diviser et corrompre.
        // Cas usuels protégés : HMR, double <script src="donnees.js">, require()
        // accidentel dans un script Node qui modifie donnees.js, etc.
        if (bd && bd.e > 0 && bd.c && !bd._voix) {
          const cPct = {};
          Object.entries(bd.c).forEach(([k, voix]) => {
            cPct[k] = voix / bd.e * 100;
          });
          bd._voix = bd.c;  // voix originales accessibles si besoin
          bd.c = cPct;
        }
      });
    });
  });
})();

// ─── Dérivation de pa pour les binômes au chargement ─────────────────────
// Décision (mai 2026) : pa du binôme n'est plus stocké dans donnees.js, il
// est dérivé systématiquement depuis binome_partis. "Le parti qui compte
// est celui de chaque candidat" → plus de divergence possible entre l'étiquette
// globale et les partis individuels. Règle paritaire : pour les binômes
// mixtes 2 vrais partis (ou 2 divers), la candidate F passe devant l'homme H.
// Voir aussi derivePaForBinome dans shared.js (même logique, helper exposé).
// Idempotent : peut être ré-exécuté sans dommage.
(function(){
  function derive(bp, sexes) {
    if (!Array.isArray(bp) || bp.length !== 2) return '';
    const a = (bp[0] || '').trim();
    const b = (bp[1] || '').trim();
    if (!a || !b) return a || b || '';
    if (a === b) return a;
    const aDiv = /^DV/i.test(a);
    const bDiv = /^DV/i.test(b);
    if (aDiv && !bDiv) return b;
    if (bDiv && !aDiv) return a;
    if (Array.isArray(sexes) && sexes.length === 2) {
      if (sexes[0] !== 'F' && sexes[1] === 'F') return b + '+' + a;
    }
    return a + '+' + b;
  }
  function apply(dict) {
    if (typeof dict === 'undefined') return;
    const hasPersons = typeof PERSONS !== 'undefined';
    Object.values(dict).forEach(c => {
      if (Array.isArray(c.binome) && c.binome.length === 2 && Array.isArray(c.binome_partis)) {
        const sexes = hasPersons ? c.binome.map(pid => (PERSONS[pid] || {}).s || '') : null;
        const derived = derive(c.binome_partis, sexes);
        if (derived) c.pa = derived;
      }
    });
  }
  apply(typeof CAND_DATA !== 'undefined' ? CAND_DATA : undefined);
  apply(typeof CANDIDATURES !== 'undefined' ? CANDIDATURES : undefined);
})();
